arguments.command:
node - <<'NODE'
const url=process.env.SUPABASE_URL;
const key=process.env.SUPABASE_SERVICE_ROLE_KEY;
const h={apikey:key,Authorization:`Bearer ${key}`};
async function get(path){const r=await fetch(`${url}/rest/v1/${path}`,{headers:h}); if(!r.ok){throw new Error(`${r.status} ${await r.text()}`)} return r.json();}
(async()=>{
 const agents=await get('agents?select=agent_id,org_unit,status,last_heartbeat_at&limit=500');
 const metrics=await get('agent_metrics?select=agent_id,error_rate,response_time_ms,memory_utilization_pct,recorded_at&order=recorded_at.desc&limit=1000');
 const now=new Date('2026-03-13T18:26:00Z');
 const stale=agents.filter(a=>!a.last_heartbeat_at || ((now - new Date(a.last_heartbeat_at))/60000)>30)
                   .map(a=>({agent_id:a.agent_id,org_unit:a.org_unit,status:a.status,last_heartbeat_at:a.last_heartbeat_at,minutes_stale:a.last_heartbeat_at?Math.round((now-new Date(a.last_heartbeat_at))/60000):null}));
 const byAgent=new Map();
 for(const m of metrics){ if(!byAgent.has(m.agent_id)) byAgent.set(m.agent_id,m); }
 const highErr=[...byAgent.values()].filter(m=>m.error_rate!=null && m.error_rate>5);
 const highResp=[...byAgent.values()].filter(m=>m.response_time_ms!=null && m.response_time_ms>2000);
 const highMem=[...byAgent.values()].filter(m=>m.memory_utilization_pct!=null && m.memory_utilization_pct>80);
 console.log(JSON.stringify({agents_total:agents.length,metrics_rows:metrics.length,stale_count:stale.length,stale_top:stale.slice(0,15),high_error_count:highErr.length,high_error_top:highErr.slice(0,10),high_resp_count:highResp.length,high_resp_top:highResp.slice(0,10),high_mem_count:highMem.length,high_mem_top:highMem.slice(0,10)},null,2));
})();
NODE

